@startuml
package C {
    class TilePyramid {
    }
    class TGCEDataType {
        <<enumeration>>
        integer
        float
    }
    class GridCellEncoding {
        <<enumeration>>
        grid-value-is-center
        grid-value-is-area
        grid-value-is-corner
    }
    class Tile {
    }
    class TiledGriddedCoverage {
        id: Integer
        dataType = tiles
        coverageDataType: TGCEDataType
        scale: Real
        offset: Real
        precision: Real?
        nullValue: Real?
        gridCellEncoding: GridCellEncoding?
        unitOfMeasure: String?
        fieldName: String?
        quantityDefinition: String?
    }
    class CoverageTile {
        scale: Real
        offset: Real
        min: Real?
        max: Real?
        mean: Real?
        standardDeviation: Real?
    }
}

TilePyramid ..> Tile
TiledGriddedCoverage ..> TilePyramid
TiledGriddedCoverage ..> CoverageTile
CoverageTile ..> TilePyramid
TiledGriddedCoverage ..> TGCEDataType
TiledGriddedCoverage ..> GridCellEncoding
TiledGriddedCoverage ..> Tile
TiledGriddedCoverage ..> CoverageTile
@enduml
